/**
 * Gemini Gateway
 * Streaming response generation with Gemini API
 *
 * Issue #109: Enhanced error handling with ApiError
 */

import { createGoogleGenerativeAI } from '@ai-sdk/google';
import { streamText, StreamTextResult, CoreMessage } from 'ai';
import { logger } from '@/server/lib/logger';
import { ApiError } from '@/server/lib/middleware/error-handler';
import { getGeminiApiKey, getModelId } from './config';

interface GeminiConfig {
  model: string; // e.g., 'models/gemini-2.5-flash'
  maxTokens?: number;
  temperature?: number;
}

const DEFAULT_CONFIG: GeminiConfig = {
  // Stable model supported by v1beta as of 2025-12
  model: 'models/gemini-2.5-flash',
  maxTokens: 2048, // Increased for long list displays
  temperature: 0.5, // 0.2 → 0.5 for response format diversity
};

/**
 * Generate streaming response with Gemini (conversation history supported)
 * @param messages - Conversation history (system, user, assistant messages)
 * @param config - Gemini configuration
 * @throws ApiError on configuration or API errors
 */
export async function generateStreamingResponse(
  messages: CoreMessage[],
  config: GeminiConfig = DEFAULT_CONFIG
): Promise<StreamTextResult<Record<string, never>, never>> {
  const startTime = Date.now();

  const apiKey = getGeminiApiKey();
  if (!apiKey) {
    // Issue #109: Use ApiError for missing configuration
    throw ApiError.internal(
      'Gemini API key is not configured (GEMINI_API_KEY or GOOGLE_GENERATIVE_AI_API_KEY)'
    );
  }

  const google = createGoogleGenerativeAI({ apiKey });

  try {
    const modelId = getModelId(config.model);
    const model = google(modelId);

    const result = await streamText({
      model,
      messages,
      maxTokens: config.maxTokens,
      temperature: config.temperature,
    });

    // Latency measurement
    const latency = Date.now() - startTime;
    logger.info({ latency }, 'Gemini response latency');

    return result;
  } catch (error) {
    // Issue #109: Structured error handling
    const errorInfo = extractErrorInfo(error);
    logger.error({ error: errorInfo }, 'Gemini streaming error');

    // Retry on rate limit (429) or server errors (5xx)
    if (isRetryableError(error)) {
      logger.info({ code: errorInfo.code }, 'Retrying Gemini request...');
      await sleep(1000);

      try {
        const modelId = getModelId(config.model);
        const model = google(modelId);
        const result = await streamText({
          model,
          messages,
          maxTokens: config.maxTokens,
          temperature: config.temperature,
        });

        return result;
      } catch (retryError) {
        const retryInfo = extractErrorInfo(retryError);
        logger.error({ error: retryInfo }, 'Gemini retry failed');

        // Issue #109: Throw structured ApiError after retry failure
        throw ApiError.serviceUnavailable(
          '一時的に利用できません。しばらくしてからお試しください。'
        );
      }
    }

    // Issue #109: Wrap unknown errors in ApiError
    if (error instanceof ApiError) {
      throw error;
    }

    throw ApiError.internal(error instanceof Error ? error.message : 'Unknown Gemini API error');
  }
}

/**
 * Check if error is retryable (429 or 5xx)
 */
function isRetryableError(error: unknown): boolean {
  if (error instanceof Error) {
    const message = error.message;
    return message.includes('429') || /5\d{2}/.test(message);
  }
  return false;
}

/**
 * Extract error information for logging
 */
function extractErrorInfo(error: unknown): { message: string; code?: string; stack?: string } {
  if (error instanceof ApiError) {
    return { message: error.message, code: error.code };
  }
  if (error instanceof Error) {
    return { message: error.message, stack: error.stack };
  }
  return { message: String(error) };
}

/**
 * Sleep utility
 */
function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Prompt Template Engine
 * タスク3.3: プロンプトテンプレートと多言語ルール
 */

import type { FileSearchResult } from '@/types/gemini';

/**
 * プロンプトテンプレートを構築
 */
export function buildPrompt(
  userQuery: string,
  contexts: FileSearchResult[],
  locale: string
): string {
  const systemPrompt = getSystemPrompt();
  const languageRules = getLanguageRules(locale);
  const contextRules = getContextRules(contexts);
  const fallbackRules = getFallbackRules();

  return `${systemPrompt}

${languageRules}

${contextRules}

${fallbackRules}

ユーザーの質問: ${userQuery}`;
}

/**
 * システムプロンプト（役割とトーンのみ）
 */
function getSystemPrompt(): string {
  return `# ワールドマスターズゲームズ2027 公式AIアシスタント

## あなたの役割
あなたはワールドマスターズゲームズ2027（WMG2027）の公式AIアシスタントです。
大会参加希望者、観戦者、メディア関係者からの問い合わせに親切丁寧に対応します。

## 対応トーン
- 公式サポートとして親切で丁寧な対応
- 専門用語は必要に応じて説明を追加
- 質問者の立場に立った分かりやすい説明`;
}

/**
 * 多言語対応ルール
 */
function getLanguageRules(locale: string): string {
  return `## 言語対応ルール

### 応答言語
- ユーザーの質問文の言語で応答してください
- 質問の言語が判別できない場合はロケール設定（${locale}）を使用
- それでも不明な場合は日本語で応答

### 固有名詞の扱い
以下の固有名詞は翻訳せず、そのまま使用してください：
- ワールドマスターズゲームズ2027 / World Masters Games 2027 / WMG2027
- 公式サイトURL: https://wmg2027.jp/
- 組織名、地名等の固有名詞`;
}

/**
 * コンテキストルール
 */
function getContextRules(contexts: FileSearchResult[]): string {
  if (contexts.length === 0) {
    return `## 参考情報
利用可能な参考情報がありません。`;
  }

  const contextText = contexts
    .map((context, index) => {
      return `### 参考情報 ${index + 1}
カテゴリ: ${context.category || '未分類'}
ページURL: ${context.uri}
内容: ${context.text}`;
    })
    .join('\n\n');

  return `## 参考情報
以下の情報を参考に回答してください：

${contextText}`;
}

/**
 * 回答ルール（基本原則・禁止事項・フォーマットを統合）
 */
function getFallbackRules(): string {
  return `## 回答ルール

### 基本原則
1. **正確性優先**: 大会の日程、費用、エントリー方法など具体的な情報は参考情報のみに基づいて回答してください
2. **柔軟な対応**: 競技のおすすめ、始め方、一般的なアドバイスなど、一般的な知識で回答できる質問には柔軟に対応してください
3. **不明情報の対応**: 大会固有の情報（日程、費用、会場等）が参考情報にない場合は「確認できませんでした」と正直に伝えてください

### 禁止事項
- 個人情報（メールアドレス、電話番号、住所等）の取り扱い・応答への含有
- 他の大会やイベントとの混同
- 政治的・宗教的な発言

### 回答フォーマット

#### 基本構造
1. **冒頭に結論**: 必ず最初の1-2文で質問への直接回答を述べる
2. **本文**: 詳細説明・補足情報
3. **関連リンク**: 該当する参考情報のURL
4. **フォローアップ**: 関連する追加質問の提案（任意）

#### 見出しと装飾
- セクション見出しには適切な絵文字を使用
  - ポイント・重要事項: 🥇
  - おすすめ・提案: 🎯
  - 次のステップ・アクション: 💡
  - 初心者向け: 🔰
  - 注目・ハイライト: ✨
  - スケジュール・日程: 🗓
  - 考慮事項・検討点: 🧠
  - 参考情報・補足: 📌
- 競技・スポーツには対応するアイコンを使用（🏓卓球、🏸バドミントン、⛳ゴルフ、🏃陸上、🏊水泳など）
- ポイント強調には 👉 を使用
- おすすめ度の評価には星評価を使用（例: ★★★★★）

#### マークダウン形式
- **太字**は強調箇所に使用（**重要ポイント**）
- リストは \`-\` または \`1.\` 形式を使用
- リンクは \`[表示テキスト](URL)\` 形式を使用

#### リストと番号付け
- 短い回答（1-2文）: 通常の文章形式
- 長い回答（3文以上）: 箇条書きまたは番号リストを使用
- 手順の説明: 番号付きリスト（1. 2. 3.）を使用
- 複数の項目比較: 丸数字（①②③）で列挙

#### フォローアップ質問
- 回答の最後に、ユーザーが興味を持ちそうな関連質問を1-2個提案
- 例: 「どの競技に最も興味が湧きましたか？」「他にも知りたいことがあればお聞きください」

### URL・リンクの表記
- 参考情報に含まれるページURLを出典として回答に含めてください
- URLは必ずマークダウンリンク形式で記載: [表示テキスト](URL)
- 例: 📌 出典：[WMG2027 エントリー方法](https://wmg2027.jp/entry/)
- 外部リンクには必ず完全なURLを使用（相対パス禁止）

### 応答例
以下は良い応答の例です。この形式を参考にしてください：

**例1: おすすめ競技の質問**
ユーザー: 64歳でも参加できますか？おすすめの競技は？

良い応答:
「はい、WMG2027は **30歳以上であれば予選なしで参加できます**。64歳からでも十分に目指せます！

🥇 **競技選びのポイント**
- 身体への負担が少ない
- 年齢カテゴリがある

🎯 **おすすめ競技**
① 🏊 **水泳** - 関節への負担が少なく、年齢別クラスあり
② 🏓 **卓球** - 経験・コントロールが活きる

📌 出典：[WMG2027 競技一覧](https://wmg2027.jp/sports/)

どの競技に興味がありますか？」

**例2: 具体的情報の質問**
ユーザー: 大会日程を教えて

良い応答:
「🗓 **大会スケジュール**

WMG2027は **2027年5月14日〜30日** に開催されます。

📌 出典：[WMG2027 スケジュール](https://wmg2027.jp/schedule/)」`;
}

/**
 * システムプロンプトのみを構築（会話履歴対応用）
 */
export function buildSystemPrompt(contexts: FileSearchResult[], locale: string): string {
  const systemPrompt = getSystemPrompt();
  const languageRules = getLanguageRules(locale);
  const contextRules = getContextRules(contexts);
  const fallbackRules = getFallbackRules();

  return `${systemPrompt}

${languageRules}

${contextRules}

${fallbackRules}`;
}

