/**
 * Gemini Configuration Module
 * Common configuration functions for Gemini API integration
 */

/**
 * Get Gemini API key from environment variables
 * Supports both GEMINI_API_KEY and GOOGLE_GENERATIVE_AI_API_KEY
 */
export function getGeminiApiKey(): string | undefined {
  return process.env.GEMINI_API_KEY || process.env.GOOGLE_GENERATIVE_AI_API_KEY;
}

/**
 * Get model ID for AI SDK (Google provider)
 * Adds 'models/' prefix if not present
 */
export function getModelId(defaultId: string): string {
  const envId = process.env.GEMINI_MODEL_ID;
  if (envId) {
    return envId.startsWith('models/') ? envId : `models/${envId}`;
  }
  return defaultId;
}

/**
 * Get model ID for @google/genai (generative model)
 * Removes 'models/' prefix if present
 */
export function getGenerativeModelId(): string {
  const envId = process.env.GEMINI_MODEL_ID;
  if (envId) {
    return envId.replace(/^models\//, '');
  }
  return 'gemini-2.5-flash';
}

