/**
 * File Search Store API
 * New SDK (@google/genai) based File Search Store implementation
 *
 * Uses fileSearch tool for semantic search across uploaded documents
 */

import { GoogleGenAI } from '@google/genai';
import { logger } from '@/server/lib/logger';
import { getGenerativeModelId } from '../config';
import type { FileSearchResult } from '@/types/gemini';
import type { Manifest } from './types';
import { buildFileSearchPrompt, extractCategories } from './prompts';
import { parseSearchResults } from './parser';
import { performLegacySearch } from './legacy-search';

/**
 * Perform search using File Search Store API (new SDK)
 */
export async function performFileSearchStoreSearch(
  apiKey: string,
  query: string,
  numResults: number,
  manifest: Manifest
): Promise<FileSearchResult[]> {
  try {
    logger.info(
      {
        totalFiles: manifest.files.length,
        version: manifest.version,
        fileSearchStoreName: manifest.file_search_store_name,
      },
      '[File Search Store] Manifest loaded'
    );

    // Fall back to legacy mode if no file_search_store_name
    if (!manifest.file_search_store_name) {
      logger.warn('[File Search Store] No file_search_store_name in manifest, using legacy mode');
      return performLegacySearch(apiKey, query, numResults, manifest);
    }

    // Create client with new SDK
    const ai = new GoogleGenAI({ apiKey });

    // Extract available categories
    const availableCategories = extractCategories(manifest.files);
    logger.info({ availableCategories }, '[File Search Store] Available categories');

    // Build search prompt (shared with legacy search)
    const searchPrompt = buildFileSearchPrompt(query, availableCategories, numResults);

    logger.info('[File Search Store] Calling Gemini API with fileSearch tool');

    // generateContent with fileSearch tool (new SDK)
    const response = await ai.models.generateContent({
      model: getGenerativeModelId(),
      contents: searchPrompt,
      config: {
        tools: [
          {
            fileSearch: {
              fileSearchStoreNames: [manifest.file_search_store_name],
            },
          },
        ],
        temperature: 0.1,
      },
    });

    // Debug: output full response structure
    logger.info(
      {
        responseKeys: Object.keys(response),
        candidates: response.candidates?.length,
        fullResponse: JSON.stringify(response).substring(0, 1000),
      },
      '[File Search Store] Full API response'
    );

    const text = response.text || '';

    logger.info(
      {
        textLength: text.length,
        preview: text.substring(0, 200),
      },
      '[File Search Store] Gemini API response'
    );

    // Log grounding metadata if available
    if (response.candidates?.[0]?.groundingMetadata) {
      logger.info(
        { groundingMetadata: response.candidates[0].groundingMetadata },
        '[File Search Store] Grounding metadata'
      );
    }

    // Parse response
    const results = parseSearchResults(text, manifest);
    logger.info(
      {
        count: results.length,
        results: results.map(r => ({
          question: r.original_question?.substring(0, 50),
          type: r.source_type,
        })),
      },
      '[File Search Store] Parsed results'
    );

    return results.slice(0, numResults);
  } catch (error) {
    logger.error({ error }, '[File Search Store] Search error');
    // Fall back to legacy mode on error
    return performLegacySearch(apiKey, query, numResults, manifest);
  }
}

